<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { Search, Server, Globe, Database, Shield, BookOpen, ChevronRight, ChevronDown } from 'lucide-vue-next'
import { docContents } from '@/data/docs'

const searchQuery = ref('')
const activeCategory = ref('ecs')
const selectedDoc = ref<string | null>(null)
const expandedMenus = ref<Set<string>>(new Set())

const categories = [
  { id: 'ecs', name: '云服务器 ECS', icon: Server },
  { id: 'cdn', name: 'CDN', icon: Globe },
  { id: 'oss', name: 'OSS', icon: Database },
  { id: 'gfip', name: '高防IP', icon: Shield },
]

interface DocItem {
  title: string
  category: string
  path: string
  parent?: string
}

interface MenuGroup {
  title: string
  items: DocItem[]
}

const menuStructure: Record<string, MenuGroup[]> = {
  ecs: [
    {
      title: '开始使用',
      items: [
        { title: '什么是云服务器ECS', category: 'ecs', path: 'ecs-introduce' },
      ]
    },
    {
      title: 'ECS产品简介',
      items: [
        { title: '产品优势', category: 'ecs', path: 'ecs-product-advantage' },
        { title: '基本概念', category: 'ecs', path: 'ecs-basic-concept' },
      ]
    },
    {
      title: '操作指南',
      items: [
        { title: '创建实例', category: 'ecs', path: 'ecs-create-instance' },
        { title: '启动实例', category: 'ecs', path: 'ecs-startup-instance' },
        { title: '停止实例', category: 'ecs', path: 'ecs-stop-instance' },
        { title: '重启实例', category: 'ecs', path: 'ecs-restart-instance' },
        { title: '重装系统', category: 'ecs', path: 'ecs-reinstall-system' },
        { title: '创建系统快照', category: 'ecs', path: 'ecs-create-system-snapshot' },
        { title: '续费包年包月实例', category: 'ecs', path: 'ecs-renew' },
        { title: '设置自动续费', category: 'ecs', path: 'ecs-autorenew' },
        { title: '升级规格', category: 'ecs', path: 'ecs-upgrades-specification' },
        { title: '磁盘扩容', category: 'ecs', path: 'ecs-disk-expansion' },
        { title: '新增数据盘', category: 'ecs', path: 'ecs-add-data-disk' },
        { title: '创建私有网络', category: 'ecs', path: 'ecs-create-private-network' },
        { title: '挂载私有网络', category: 'ecs', path: 'ecs-hangover-private-network' },
        { title: '升级带宽', category: 'ecs', path: 'ecs-upgrades-bandwith' },
        { title: '安全组', category: 'ecs', path: 'ecs-security-group' },
      ]
    }
  ],
  cdn: [
    {
      title: 'CDN',
      items: [
        { title: '什么是CDN', category: 'cdn', path: 'cdn-introduce' },
        { title: '产品优势', category: 'cdn', path: 'cdn-product-advantage' },
        { title: '基本概念', category: 'cdn', path: 'cdn-basic-concept' },
      ]
    }
  ],
  oss: [
    {
      title: 'OSS',
      items: [
        { title: '什么是OSS', category: 'oss', path: 'oss-introduce' },
        { title: '产品优势', category: 'oss', path: 'oss-product-advantage' },
        { title: '基本概念', category: 'oss', path: 'oss-basic-concept' },
      ]
    }
  ],
  gfip: [
    {
      title: '高防IP',
      items: [
        { title: '什么是高防IP', category: 'gfip', path: 'gfip-introduce' },
        { title: '产品优势', category: 'gfip', path: 'gfip-product-advantage' },
        { title: '基本概念', category: 'gfip', path: 'gfip-basic-concept' },
      ]
    }
  ],
}

const allDocs: DocItem[] = Object.values(menuStructure).flatMap(groups => 
  groups.flatMap(group => group.items)
)

const filteredDocs = computed(() => {
  let docs = allDocs
  if (searchQuery.value) {
    const q = searchQuery.value.toLowerCase()
    docs = docs.filter(d => d.title.toLowerCase().includes(q))
  }
  return docs
})

const searchResults = computed(() => searchQuery.value.length > 0)

const groupedDocs = computed(() => {
  if (!searchResults.value) return {}
  const groups: Record<string, DocItem[]> = {}
  filteredDocs.value.forEach(doc => {
    if (!groups[doc.category]) groups[doc.category] = []
    groups[doc.category].push(doc)
  })
  return groups
})

const categoryNameMap: Record<string, string> = {
  ecs: '云服务器',
  cdn: 'CDN',
  oss: 'OSS',
  gfip: '高防IP',
}

const currentDocContent = computed(() => {
  if (!selectedDoc.value) return null
  return docContents[selectedDoc.value] || null
})

const selectDoc = (path: string) => {
  selectedDoc.value = path
}

const toggleMenu = (title: string) => {
  const newSet = new Set(expandedMenus.value)
  if (newSet.has(title)) {
    newSet.delete(title)
  } else {
    newSet.add(title)
  }
  expandedMenus.value = newSet
}

const isMenuExpanded = (title: string) => {
  return expandedMenus.value.has(title)
}

onMounted(() => {
  const structure = menuStructure[activeCategory.value]
  if (structure && structure.length > 0) {
    expandedMenus.value.add(structure[0].title)
    if (structure[0].items.length > 0) {
      selectedDoc.value = structure[0].items[0].path
    }
  }
})
</script>

<template>
  <div class="min-h-screen bg-white dark:bg-gray-950 pt-12 lg:pt-14">
    <div class="border-b border-gray-200 dark:border-gray-800">
      <div class="mx-auto px-4">
        <div class="flex items-center justify-between py-4">
          <div class="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400">
            <a href="/" class="hover:text-blue-600 dark:hover:text-blue-400">首页</a>
            <span>/</span>
            <span class="text-gray-900 dark:text-white">文档中心</span>
          </div>
          <div class="relative w-96">
            <Search class="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              v-model="searchQuery"
              type="text"
              placeholder="输入相关关键词进行搜索"
              class="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-700 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 dark:bg-gray-800 dark:text-white"
            />
          </div>
        </div>
      </div>
    </div>

    <div class="mx-auto px-4">
      <div class="flex">
        <div class="w-64 shrink-0 border-r border-gray-200 dark:border-gray-800 min-h-[calc(100vh-112px)]">
          <div class="py-4">
            <div class="text-xs text-gray-500 dark:text-gray-500 px-4 mb-2">在结果中筛选</div>
            <div class="space-y-1">
              <button
                v-for="cat in categories"
                :key="cat.id"
                :class="[
                  'w-full text-left px-4 py-2 text-sm transition-colors',
                  activeCategory === cat.id
                    ? 'bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400'
                    : 'text-gray-700 hover:bg-gray-100 dark:text-gray-300 dark:hover:bg-gray-800',
                ]"
                @click="activeCategory = cat.id; searchQuery = ''"
              >
                <div class="flex items-center gap-2">
                  <component :is="cat.icon" class="w-4 h-4" />
                  {{ cat.name }}
                </div>
              </button>
            </div>
          </div>

          <div class="pt-4" v-if="!searchResults">
            <div class="text-xs text-gray-500 dark:text-gray-500 px-4 mb-2">{{ categoryNameMap[activeCategory] }}</div>
            <div class="space-y-1">
              <template v-for="group in menuStructure[activeCategory]" :key="group.title">
                <button
                  @click="toggleMenu(group.title)"
                  class="w-full flex items-center justify-between px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800"
                >
                  <span>{{ group.title }}</span>
                  <component :is="isMenuExpanded(group.title) ? ChevronDown : ChevronRight" class="w-4 h-4" />
                </button>
                <div v-if="isMenuExpanded(group.title)" class="pl-4 space-y-1">
                  <button
                    v-for="doc in group.items"
                    :key="doc.path"
                    :class="[
                      'w-full text-left px-4 py-1.5 text-sm transition-colors rounded',
                      selectedDoc === doc.path
                        ? 'text-blue-600 dark:text-blue-400 font-medium'
                        : 'text-gray-600 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white',
                    ]"
                    @click="selectDoc(doc.path)"
                  >
                    {{ doc.title }}
                  </button>
                </div>
              </template>
            </div>
          </div>
        </div>

        <div class="flex-1 px-8 py-6">
          <div v-if="searchResults">
            <h2 class="text-xl font-bold text-gray-900 dark:text-white mb-6">
              搜索结果 "{{ searchQuery }}"（{{ filteredDocs.length }} 条）
            </h2>
            <div v-if="filteredDocs.length === 0" class="text-center py-12">
              <p class="text-gray-500 dark:text-gray-400">未找到相关文档</p>
            </div>
            <div v-else class="space-y-6">
              <div v-for="(docs, catId) in groupedDocs" :key="catId">
                <h3 class="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">{{ categoryNameMap[catId] }}</h3>
                <div class="grid gap-2">
                  <button
                    v-for="doc in docs"
                    :key="doc.path"
                    class="w-full flex items-center gap-3 p-4 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors group text-left border border-gray-200 dark:border-gray-700"
                    @click="selectDoc(doc.path); searchQuery = ''"
                  >
                    <BookOpen class="w-4 h-4 text-blue-500 shrink-0" />
                    <span class="text-gray-700 dark:text-gray-200 group-hover:text-blue-500 transition-colors flex-1">{{ doc.title }}</span>
                    <ChevronRight class="w-4 h-4 text-gray-400" />
                  </button>
                </div>
              </div>
            </div>
          </div>

          <div v-else-if="currentDocContent" class="prose prose-sm max-w-none prose-headings:font-semibold prose-h1:text-2xl prose-h2:text-xl prose-h3:text-lg prose-h4:text-base prose-p:text-gray-700 dark:prose-invert dark:prose-p:text-gray-300">
            <h1>{{ currentDocContent.title }}</h1>
            <div class="space-y-4">
              <template v-for="(item, index) in currentDocContent.content" :key="index">
                <div v-if="item.type === 'table'" class="overflow-x-auto">
                  <table class="w-full border-collapse border border-gray-300 dark:border-gray-600">
                    <thead>
                      <tr class="bg-gray-50 dark:bg-gray-800">
                        <th v-for="(header, hi) in item.headers" :key="hi" class="border border-gray-300 dark:border-gray-600 px-4 py-2 text-left text-sm font-medium">
                          {{ header }}
                        </th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr v-for="(row, ri) in item.rows" :key="ri">
                        <td v-for="(cell, ci) in row" :key="ci" class="border border-gray-300 dark:border-gray-600 px-4 py-2 text-sm">
                          <span v-if="typeof cell === 'object' && cell.type === 'link'" class="text-blue-600 dark:text-blue-400 cursor-pointer hover:underline">{{ cell.text }}</span>
                          <span v-else>{{ cell }}</span>
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>

                <div v-else-if="item.type === 'note'" class="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 p-4">
                  <p class="text-blue-800 dark:text-blue-300 text-sm">{{ item.content }}</p>
                </div>

                <h3 v-else-if="item.type === 'heading'">{{ item.content }}</h3>

                <p v-else-if="item.type === 'text'">{{ item.content }}</p>

                <ul v-else-if="item.type === 'list'" class="space-y-2">
                  <li v-for="(li, liIndex) in item.content" :key="liIndex">{{ li }}</li>
                </ul>

                <p v-else-if="item.type === 'strong'"><strong>{{ item.content }}</strong></p>
              </template>
            </div>
          </div>
        </div>

        <div v-if="currentDocContent && !searchResults" class="w-56 shrink-0 border-l border-gray-200 dark:border-gray-800 pl-6 py-6">
          <div class="sticky top-24">
            <h4 class="text-sm font-semibold text-gray-900 dark:text-white mb-3">本页导读</h4>
            <nav class="space-y-2">
              <template v-for="(item, index) in currentDocContent.content" :key="index">
                <a v-if="item.type === 'heading'" href="#" class="block text-sm text-gray-600 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                  {{ item.content }}
                </a>
              </template>
            </nav>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
